// // This module selects data from two 64-bit input sources based on a 2-bit selection signal. When sel is 00, the output will be the upper 32 bits of in0; when sel is 01, the output will be the lower 32 bits of in0; when sel is 10, the output will be the upper 32 bits of in1; and when sel is 11, the output will be the lower 32 bits of in1.
module top_module(
  input [63:0] in0,
  input [63:0] in1,
  input [1:0] sel,
  output reg [63:0] out
);always @(*) begin
    case(sel)
      2'b00: out = in0[31:0];
      2'b01: out = in0[63:32];
      2'b10: out = in1[31:0];
      2'b11: out = in1[63:32];
    endcase
  end

endmodule
